import React from 'react';
import { FaSignOutAlt, FaUser, FaHeartbeat } from 'react-icons/fa';

const Navbar = ({ user, onLogout }) => {
  return (
    <nav className="fixed top-0 left-0 right-0 bg-white/95 backdrop-blur-lg shadow-lg z-50 border-b border-blue-100">
      <div className="container mx-auto px-6">
        <div className="flex items-center justify-between h-16">
          {/* Enhanced Logo */}
          <div className="flex items-center gap-3">
            <div className="relative w-10 h-10">
              <div className="absolute inset-0 bg-gradient-to-r from-blue-600 to-green-600 rounded-2xl shadow-lg"></div>
              <div className="relative bg-gradient-to-r from-blue-600 to-green-600 rounded-2xl flex items-center justify-center w-full h-full transform hover:scale-110 transition-transform duration-300">
                <FaHeartbeat className="text-white text-lg animate-pulse" />
              </div>
            </div>
            <div>
              <span className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-green-600 bg-clip-text text-transparent">
                Helio
              </span>
              <div className="text-xs text-gray-500 font-medium">Healthcare Platform</div>
            </div>
          </div>

          {/* Enhanced User info and logout */}
          {user && (
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-3 bg-blue-50 px-4 py-2 rounded-2xl border border-blue-100">
                <div className="w-8 h-8 bg-gradient-to-r from-blue-500 to-indigo-600 rounded-full flex items-center justify-center">
                  <FaUser className="text-white text-sm" />
                </div>
                <div className="text-left">
                  <div className="text-sm font-semibold text-gray-800">
                    {user.profile?.first_name || user.username}
                  </div>
                  <div className="text-xs text-blue-600 capitalize font-medium">
                    {user.role}
                  </div>
                </div>
              </div>
              {onLogout && (
                <button
                  onClick={onLogout}
                  className="flex items-center gap-2 px-4 py-2 text-red-600 hover:text-white hover:bg-red-500 bg-red-50 border border-red-200 hover:border-red-500 rounded-2xl transition-all duration-300 transform hover:scale-105 shadow-sm hover:shadow-lg"
                  title="Logout"
                >
                  <FaSignOutAlt className="text-sm" />
                  <span className="text-sm font-medium">Logout</span>
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
